class ItemNotFoundError(Exception):
    pass


class Store:
    def __init__(self):
        self._data = {}

    def add(self, item_id, item):
        self._data[item_id] = item.copy()

    def get(self, item_id):
        if item_id not in self._data:
            raise ItemNotFoundError(item_id)
        return self._data[item_id].copy()

    def delete(self, item_id):
        if item_id not in self._data:
            raise ItemNotFoundError(item_id)
        del self._data[item_id]

    def list_all(self):
        return [v.copy() for v in self._data.values()]

    def find_by_category(self, category):
        return [v.copy() for v in self._data.values() if v.get("category") == category]

    def update(self, item_id, updates):
        if item_id not in self._data:
            raise ItemNotFoundError(item_id)
        self._data[item_id].update(updates)

