class Logic:
    def __init__(self, store):
        self.store = store
        self._list_cache = None

    def add_item(self, item_id, name, price, category="general"):
        item = {"id": item_id, "name": name, "price": price, "category": category}
        self.store.add(item_id, item)
        self._list_cache = None
        return item

    def get_item(self, item_id):
        return self.store.get(item_id)

    def delete_item(self, item_id):
        self.store.delete(item_id)
        # BUG: should clear self._list_cache = None here but doesn't

    def list_items(self):
        if self._list_cache is None:
            self._list_cache = self.store.list_all()
        return self._list_cache

    def search_by_category(self, category):
        # BUG: should normalize category to .lower() before passing to store
        return self.store.find_by_category(category)

    def calculate_total(self, item_id, quantity, discount=0):
        item = self.store.get(item_id)
        # discount should be float but may come as string from API
        total = item["price"] * quantity * (1 - discount / 100)
        return round(total, 2)

