from logic import Logic
from store import Store, ItemNotFoundError


class API:
    def __init__(self):
        self.logic = Logic(Store())

    def handle_add(self, item_id, name, price, category="general"):
        return self.logic.add_item(item_id, name, float(price), category)

    def handle_get(self, item_id):
        try:
            return {"status": 200, "data": self.logic.get_item(item_id)}
        except ItemNotFoundError:
            return {"status": 404, "error": "Not found"}

    def handle_delete(self, item_id):
        try:
            self.logic.delete_item(item_id)
            return {"status": 200}
        except ItemNotFoundError:
            return {"status": 404, "error": "Not found"}

    def handle_list(self):
        return {"status": 200, "data": self.logic.list_items()}

    def handle_search(self, category):
        return {"status": 200, "data": self.logic.search_by_category(category)}

    def handle_purchase(self, item_id, quantity, discount="0"):
        # BUG: discount comes as string from "HTTP params", should convert to float
        try:
            total = self.logic.calculate_total(item_id, int(quantity), discount=discount)
            return {"status": 200, "total": total}
        except ItemNotFoundError:
            return {"status": 404, "error": "Not found"}
